  ('activity_multipliers', '{"sedentary":1.2,"light":1.375,"moderate":1.55,"very":1.725,"extreme":1.9}'::jsonb),
  ('goal_deltas', '{"fat_loss":{"kcal_per_day":[-500,-250],"max_rate_kg_wk":1,"floor":"never below BMR"},"recomp":{"kcal_per_day":[0,0]},"muscle_gain":{"surplus_pct":[0.1,0.15],"kcal_per_lb_bw":[10,12]},"energy_per_kg_fat":7700,"energy_per_lb_fat":3500}'::jsonb),
  ('atwater_factors', '{"protein":4,"carbs":4,"fat":9}'::jsonb),
